// src/pages/ImageProject.js

import React, { useState, useRef } from 'react';
import Webcam from 'react-webcam';
import './ImageProject.css'; // Import the CSS file

const ImageProject = () => {
  const [class1Mode, setClass1Mode] = useState(null);
  const [class2Mode, setClass2Mode] = useState(null);
  const webcamRef1 = useRef(null);
  const webcamRef2 = useRef(null);
  const [capturedImages1, setCapturedImages1] = useState([]);
  const [capturedImages2, setCapturedImages2] = useState([]);

  const handleCapture1 = () => {
    if (webcamRef1.current) {
      const imageSrc = webcamRef1.current.getScreenshot();
      setCapturedImages1(prevImages => [...prevImages, imageSrc]);
    }
  };

  const handleCapture2 = () => {
    if (webcamRef2.current) {
      const imageSrc = webcamRef2.current.getScreenshot();
      setCapturedImages2(prevImages => [...prevImages, imageSrc]);
    }
  };

  const deleteImage1 = (index) => {
    setCapturedImages1(prevImages => prevImages.filter((_, i) => i !== index));
  };

  const deleteImage2 = (index) => {
    setCapturedImages2(prevImages => prevImages.filter((_, i) => i !== index));
  };

  return (
    <div className="container">
      <h1>Image Project</h1>
      <div className="class-section">
        <h2>Class 1</h2>
        <button onClick={() => setClass1Mode('upload')}>Upload Image</button>
        <button onClick={() => setClass1Mode('capture')}>Capture Image</button>
        {class1Mode === 'capture' && (
          <div className="webcam-container">
            <Webcam
              audio={false}
              ref={webcamRef1}
              screenshotFormat="image/jpeg"
              width={320}
              height={240}
            />
            <button onClick={handleCapture1}>Capture</button>
            <div className="captured-images">
              {capturedImages1.length > 0 && <h3>Captured Images (Class 1):</h3>}
              {capturedImages1.map((image, index) => (
                <div key={index} className="image-wrapper">
                  <img src={image} alt={`Class 1 Capture ${index + 1}`} />
                  <button className="delete-btn" onClick={() => deleteImage1(index)}>
                    ❌
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}
        {class1Mode === 'upload' && (
          <input type="file" accept="image/*" onChange={(e) => console.log('Class 1 Uploaded Image:', e.target.files[0])} />
        )}
      </div>
      <div className="class-section">
        <h2>Class 2</h2>
        <button onClick={() => setClass2Mode('upload')}>Upload Image</button>
        <button onClick={() => setClass2Mode('capture')}>Capture Image</button>
        {class2Mode === 'capture' && (
          <div className="webcam-container">
            <Webcam
              audio={false}
              ref={webcamRef2}
              screenshotFormat="image/jpeg"
              width={320}
              height={240}
            />
            <button onClick={handleCapture2}>Capture</button>
            <div className="captured-images">
              {capturedImages2.length > 0 && <h3>Captured Images (Class 2):</h3>}
              {capturedImages2.map((image, index) => (
                <div key={index} className="image-wrapper">
                  <img src={image} alt={`Class 2 Capture ${index + 1}`} />
                  <button className="delete-btn" onClick={() => deleteImage2(index)}>
                    ❌
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}
        {class2Mode === 'upload' && (
          <input type="file" accept="image/*" onChange={(e) => console.log('Class 2 Uploaded Image:', e.target.files[0])} />
        )}
      </div>
    </div>
  );
};

export default ImageProject;
